/**
 * Shared in-memory option chain cache.
 *
 * Chains are generated by the simulation engine (marketApi → syntheticChain),
 * anchored on a live spot price. The cache exists to (a) avoid re-pricing the
 * full chain on every request and (b) reuse the last good build if a spot
 * fetch ever hiccups, so the chain is always available.
 *
 * TTL: 15 s during market hours, 5 min outside.
 * Dedup: concurrent requests for the same key share one build.
 * Rate-limit guard: min 3 s between live spot fetches per symbol+expiry.
 */

import {
  UNDERLYING,
  fetchOptionChain as marketFetch,
  transformChain   as marketTransform,
} from "./marketApi";

const cache     = new Map(); // key → { data, timestamp }
const pending   = new Map(); // key → Promise
const lastFetch = new Map(); // key → timestamp

const MIN_FETCH_INTERVAL_MS = 3_000;

function isMarketOpen() {
  const ist = new Date(Date.now() + (5 * 60 + 30) * 60 * 1000);
  const day = ist.getUTCDay();
  if (day === 0 || day === 6) return false;
  const mins = ist.getUTCHours() * 60 + ist.getUTCMinutes();
  return mins >= 9 * 60 + 15 && mins < 15 * 60 + 30;
}

/**
 * Returns { data, fromCache, source, cacheAgeSeconds }.
 * Throws only when no data is available (caller should return 503).
 */
export async function getChain(symbol, expiry) {
  if (!UNDERLYING[symbol]) throw new Error(`Unknown symbol: ${symbol}`);

  const key = `${symbol}_${expiry}`;
  const now = Date.now();
  const ttl = isMarketOpen() ? 15_000 : 5 * 60_000;

  // 1. Fresh cache
  const cached = cache.get(key);
  if (cached && now - cached.timestamp < ttl) {
    return { data: cached.data, fromCache: true, source: "simulated-cached",
             cacheAgeSeconds: Math.round((now - cached.timestamp) / 1000) };
  }

  // 2. Dedup in-flight builds
  if (pending.has(key)) return pending.get(key);

  // 3. Rate-limit guard
  const last = lastFetch.get(key) ?? 0;
  if (now - last < MIN_FETCH_INTERVAL_MS && cached) {
    return { data: cached.data, fromCache: true, source: "simulated-cached",
             cacheAgeSeconds: Math.round((now - cached.timestamp) / 1000) };
  }

  // 4. Build a fresh chain (live spot anchor + Black-Scholes pricing)
  const fetchPromise = (async () => {
    lastFetch.set(key, Date.now());
    try {
      const raw  = await marketFetch(symbol, expiry);
      const data = marketTransform(raw);
      cache.set(key, { data, timestamp: Date.now() });
      return { data, fromCache: false, source: "simulated", cacheAgeSeconds: 0 };
    } catch (err) {
      // A previous build beats an error — serve it slightly stale.
      const stale = cache.get(key);
      if (stale) {
        console.warn(`[chain] Build failed (${err.message}); serving cached chain`);
        return { data: stale.data, fromCache: true, source: "simulated-stale",
                 cacheAgeSeconds: Math.round((Date.now() - stale.timestamp) / 1000) };
      }
      throw err; // → 503 (should be unreachable: spot has a baseline fallback)
    } finally {
      pending.delete(key);
    }
  })();

  pending.set(key, fetchPromise);
  return fetchPromise;
}
